  ('diplomatic-823d6974-moex-00226', 'diplomatic-823d6974', 'diplomatic-823d6974-moex-113-c655adf3', 'sub-diplomatic-823d6974-05', NULL, 'single_choice', '有關臺灣地區與大陸地區人民關係條例相關規定，下列敘述何者錯誤？', '["該條例關於大陸地區人民之規定，於大陸地區人民旅居國外者，不適用之", "大陸委員會統籌處理有關大陸事務，為本條例之主管機關", "該條例第1條第一句話是：「國家統一前」", "行政院得設立或指定機構，處理兩岸人民往來有關之事務"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:36+00:00", "source_pdf_sha1": "83b516588eb6", "answer_pdf_sha1": "eaf954f80a79", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "104", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-阿拉伯文組"}'::jsonb, NULL),
  ('diplomatic-823d6974-moex-00227', 'diplomatic-823d6974', 'diplomatic-823d6974-moex-113-c655adf3', 'sub-diplomatic-823d6974-05', NULL, 'single_choice', '近年來與中共有明顯海上衝突的國家，是下列那兩個？', '["日本與菲律賓", "日本與新加坡", "菲律賓與馬來西亞", "馬來西亞與泰國"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:36+00:00", "source_pdf_sha1": "83b516588eb6", "answer_pdf_sha1": "eaf954f80a79", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "104", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-阿拉伯文組"}'::jsonb, NULL),
  ('diplomatic-823d6974-moex-00228', 'diplomatic-823d6974', 'diplomatic-823d6974-moex-113-c655adf3', 'sub-diplomatic-823d6974-05', NULL, 'single_choice', '有關中共僑務工作的敘述何者錯誤？', '["最高主管單位是國務院僑務辦公室，簡稱「國僑辦」", "中共各省、市、自治區都設有僑務工作相關辦公室", "中共僑務工作為「國僑辦」所專屬，外交部並不負責", "「國僑辦」在2018年併入中共中央統一戰線工作部"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:36+00:00", "source_pdf_sha1": "83b516588eb6", "answer_pdf_sha1": "eaf954f80a79", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "104", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-阿拉伯文組"}'::jsonb, NULL),
  ('diplomatic-823d6974-moex-00229', 'diplomatic-823d6974', 'diplomatic-823d6974-moex-113-c655adf3', 'sub-diplomatic-823d6974-05', NULL, 'single_choice', '有關中共「一帶一路」的敘述，下列何者錯誤？', '["是中共總書記胡錦濤在2013年提出，協助外國進行基礎建設", "全名是「絲綢之路經濟帶」與「21世紀海上絲綢之路」", "搭配成立「亞洲基礎設施投資銀行」以提供外國貸款", "義大利在2023年宣布退出"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:36+00:00", "source_pdf_sha1": "83b516588eb6", "answer_pdf_sha1": "eaf954f80a79", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "104", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-阿拉伯文組"}'::jsonb, NULL),
  ('diplomatic-823d6974-moex-00230', 'diplomatic-823d6974', 'diplomatic-823d6974-moex-113-c655adf3', 'sub-diplomatic-823d6974-05', NULL, 'single_choice', '對於「海協會」的敘述，下列何者錯誤？', '["全名是海峽兩岸關係協會", "是中共處理兩岸事務的單位，對口單位是我國的財團法人海峽交流基金會", "為一民間機構，不受中共黨政機關所控制", "現任會長是張志軍，為前任國台辦主任"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:36+00:00", "source_pdf_sha1": "83b516588eb6", "answer_pdf_sha1": "eaf954f80a79", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "104", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-阿拉伯文組"}'::jsonb, NULL),
  ('diplomatic-823d6974-moex-00231', 'diplomatic-823d6974', 'diplomatic-823d6974-moex-113-c655adf3', 'sub-diplomatic-823d6974-05', NULL, 'single_choice', '賴清德總統在2024年5月就職演說中，強調會堅守蔡英文前總統在2021年提出的「四個堅持」。下列何 者非「四個堅持」的內容？', '["永遠堅持自由民主的憲政體制", "堅持中華民國與中華人民共和國互不隸屬", "堅持中華民國臺灣的前途，必須遵循全體臺灣人民的意志", "堅持臺灣主權獨立"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:36+00:00", "source_pdf_sha1": "83b516588eb6", "answer_pdf_sha1": "eaf954f80a79", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "104", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-阿拉伯文組"}'::jsonb, NULL),
  ('diplomatic-823d6974-moex-00232', 'diplomatic-823d6974', 'diplomatic-823d6974-moex-113-c655adf3', 'sub-diplomatic-823d6974-05', NULL, 'single_choice', '半總統制國家依總統或總理所掌握之行政權大小又分為總理－總統制及總統－總理制；請問下列何者 為半總統制國家？', '["印度", "俄羅斯", "瑞典", "新加坡"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:36+00:00", "source_pdf_sha1": "83b516588eb6", "answer_pdf_sha1": "eaf954f80a79", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "104", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-阿拉伯文組"}'::jsonb, NULL),
  ('diplomatic-823d6974-moex-00233', 'diplomatic-823d6974', 'diplomatic-823d6974-moex-113-c655adf3', 'sub-diplomatic-823d6974-05', NULL, 'single_choice', '關於冷戰時期同屬社會主義陣營的中共與前蘇聯之改革開放經驗，下列敘述何者正確？', '["中共的改革有其時序，先政後經，但仍維持共產黨一黨專政的地位", "前蘇聯的改革是以一套長期的政策來建立市場經濟，以達宏觀經濟穩定", "兩國的改革開放皆面臨因經濟與生產工具由國家轉移到私人手中所致的貪污", "前蘇聯的改革模式為「漸進模式」，中共為「震盪療法」"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:36+00:00", "source_pdf_sha1": "83b516588eb6", "answer_pdf_sha1": "eaf954f80a79", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "104", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-阿拉伯文組"}'::jsonb, NULL),
  ('diplomatic-823d6974-moex-00234', 'diplomatic-823d6974', 'diplomatic-823d6974-moex-113-c655adf3', 'sub-diplomatic-823d6974-05', NULL, 'single_choice', '印度人民黨（BJP）自2014年以來連續贏得三次國會下議院大選（2014、2019、2024年），莫迪（Narendra Mosi）也於2024年6月之後展開其第三任任期。關於印度政黨與民主政治，下列敘述何者錯誤？', '["印度人民黨成立於1984年，為一印度教民族主義政黨，以宗教信仰為其主要的政治動員基礎", "印度人民黨本身開始受到全國性的注意，是在該黨關於應該如何處置那些在奧圖曼帝國侵略後於原 本印度教寺廟所在地興建的清真寺之相關言論", "印度人民黨執政之後所帶來的重要意涵，為該黨試圖轉化印度獨立之初所建立的世俗性政治與法律 制度", "印度人民黨已經和許多商業團體發展不錯的關係，它的意識型態重點為「印度性」，而非經濟孤立 主義"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:36+00:00", "source_pdf_sha1": "83b516588eb6", "answer_pdf_sha1": "eaf954f80a79", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "104", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-阿拉伯文組"}'::jsonb, NULL),
  ('diplomatic-823d6974-moex-00235', 'diplomatic-823d6974', 'diplomatic-823d6974-moex-113-c655adf3', 'sub-diplomatic-823d6974-05', NULL, 'single_choice', '中共經濟快速發展並成為世界主要強權之一後，外界所關注的重要問題是中共是否會如現代化理論論 點一樣走向自由民主。關於中共改革開放以來的政治發展，下列敘述何者錯誤？', '["1989年的天安門事件是中共建政之後所遭遇的統治正當性嚴重危機", "1989年之後中共權力結構的進一步鞏固，確認了「新威權主義」的復甦", "中共在地方層級引進多黨競爭性選舉，被視為政治民主化的鼓勵性指標", "中共威權統治下出色的經濟表現，是支持共產政權統治正當性的關鍵因素"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:36+00:00", "source_pdf_sha1": "83b516588eb6", "answer_pdf_sha1": "eaf954f80a79", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "104", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-阿拉伯文組"}'::jsonb, NULL)
